INSERT INTO kyyy_reading_passage (
    passage_code, exam_direction, source_year, source_name, passage_no, title, passage_text,
    question_count, total_score, status, sort_no, created_by
) VALUES (
    'kyyy-e1-2009-text4',
    'english_one',
    2009,
    '2009 年考研英语（一）阅读理解',
    4,
    NULL,
    'The most thoroughly studied intellectuals in the history of the New World are the ministers and political leaders of seventeenth-century New England. According to the standard history of American philosophy, nowhere else in colonial America was “so much importance attached to intellectual pursuits.” According to many books and articles, New England’s leaders established the basic themes and preoccupations of an unfolding, dominant Puritan tradition in American intellectual life. To take this approach to the New Englanders normally means to start with the Puritans’ theological innovations and their distinctive ideas about the church—important subjects that we may not neglect. But in keeping with our examination of southern intellectual life, we may consider the original Puritans as carriers of European culture, adjusting to New World circumstances. The New England colonies were the scenes of important episodes in the pursuit of widely understood ideals of civility and virtuosity. The early settlers of Massachusetts Bay included men of impressive education and influence in England. Besides the ninety or so learned ministers who came to Massachusetts churches in the decade after 1629, there were political leaders like John Winthrop, an educated gentleman, lawyer, and official of the Crown before he journeyed to Boston. These men wrote and published extensively, reaching both New World and Old World audiences, and giving New England an atmosphere of intellectual earnestness. We should not forget, however, that most New Englanders were less well educated. While few craftsmen or farmers, let alone dependents and servants, left literary compositions to be analyzed, it is obvious that their views were less fully intellectualized. Their thinking often had a traditional superstitious quality. A tailor named John Dane, who emigrated in the late 1630s, left an account of his reasons for leaving England that is filled with signs. Sexual confusion, economic frustrations, and religious hope—all came together in a decisive moment when he opened the Bible, told his father the first line he saw would settle his fate, and read the magical words: “Come out from among them, touch no unclean thing, and I will be your God and you shall be my people.” One wonders what Dane thought of the careful sermons explaining the Bible that he heard in Puritan churches. Meanwhile, many settlers had slighter religious commitments than Dane’s, as one clergyman learned in confronting folk along the coast who mocked that they had not come to the New World for religion. “Our main end was to catch fish.”',
    5,
    5.00,
    1,
    20094,
    NULL
) ON DUPLICATE KEY UPDATE
    exam_direction = VALUES(exam_direction),
    source_year = VALUES(source_year),
    source_name = VALUES(source_name),
