INSERT INTO kyyy_reading_passage (
    passage_code, exam_direction, source_year, source_name, passage_no, title, passage_text,
    question_count, total_score, status, sort_no, created_by
) VALUES (
    'kyyy-e1-2012-text1',
    'english_one',
    2012,
    '2012 年考研英语（一）阅读理解',
    1,
    NULL,
    'Come on—Everybody’s doing it. That whispered message, half invitation and half forcing, is what most of us think of when we hear the words peer pressure. It usually leads to no good—drinking, drugs and casual sex. But in her new book Join the Club, Tina Rosenberg contends that peer pressure can also be a positive force through what she calls the social cure, in which organizations and officials use the power of group dynamics to help individuals improve their lives and possibly the world. Rosenberg, the recipient of a Pulitzer Prize, offers a host of examples of the social cure in action: In South Carolina, a state-sponsored antismoking program called Rage Against the Haze sets out to make cigarettes uncool. In South Africa, an HIV-prevention initiative known as loveLife recruits young people to promote safe sex among their peers. The idea seems promising, and Rosenberg is a perceptive observer. Her critique of the lameness of many public-health campaigns is spot-on: they fail to mobilize peer pressure for healthy habits, and they demonstrate a seriously flawed understanding of psychology. “Dare to be different, please don’t smoke!” pleads one billboard campaign aimed at reducing smoking among teenagers—teenagers, who desire nothing more than fitting in. Rosenberg argues convincingly that public-health advocates ought to take a page from advertisers, so skilled at applying peer pressure. But on the general effectiveness of the social cure, Rosenberg is less persuasive. Join the Club is filled with too much irrelevant detail and not enough exploration of the social and biological factors that make peer pressure so powerful. The most glaring flaw of the social cure as it’s presented here is that it doesn’t work very well for very long. Rage Against the Haze failed once state funding was cut. Evidence that the loveLife program produces lasting changes is limited and mixed. There’s no doubt that our peer groups exert enormous influence on our behavior. An emerging body of research shows that positive health habits—as well as negative ones—spread through networks of friends via social communication. This is a subtle form of peer pressure: we unconsciously imitate the behavior we see every day. Far less certain, however, is how successfully experts and bureaucrats can select our peer groups and steer their activities in virtuous directions. It’s like the teacher who breaks up the troublemakers in the back row by pairing them with better-behaved classmates. The tactic never really works. And that’s the problem with a social cure engineered from the outside: in the real world, as in school, we insist on choosing our own friends.',
    5,
    5.00,
    1,
    20121,
    NULL
) ON DUPLICATE KEY UPDATE
    exam_direction = VALUES(exam_direction),
    source_year = VALUES(source_year),
    source_name = VALUES(source_name),
    passage_no = VALUES(passage_no),
    title = VALUES(title),
    passage_text = VALUES(passage_text),
    question_count = VALUES(question_count),
    total_score = VALUES(total_score),
    status = VALUES(status),
    sort_no = VALUES(sort_no),
    created_by = VALUES(created_by);

