INSERT INTO kyyy_reading_passage (
    passage_code, exam_direction, source_year, source_name, passage_no, title, passage_text,
    question_count, total_score, status, sort_no, created_by
) VALUES (
    'kyyy-e1-2022-text1',
    'english_one',
    2022,
    '2022 年考研英语（一）阅读理解',
    1,
    NULL,
    'People often complain that plastics are too durable. Water bottles, shopping bags, and other trash litter the planet, from Mount Everest to the Mariana Trench, because plastics are everywhere and don’t break down easily. But some plastic materials change over time. They crack and frizzle. They “weep” out additives. They melt into sludge. All of which creates huge headaches for institutions, such as museums, trying to preserve culturally important objects. The variety of plastic objects at risk is dizzying: early radios, avant-garde sculptures, celluloid animation stills from Disney films, the first artificial heart. Certain artifacts are especially vulnerable because some pioneers in plastic art didn’t always know how to mix ingredients properly, says Thea van Oosten, a polymer chemist who, until retiring a few years ago, worked for decades at the Cultural Heritage Agency of the Netherlands (RCE). “It’s like baking a cake: If you don’t have exact amounts, it goes wrong,” she says. “The object you make is already a time bomb.” And sometimes, it’s not the artist’s fault. In the 1960s, the Italian artist Piero Gilardi began to create hundreds of bright, colorful foam pieces. Those pieces included small beds of roses and other items as well as a few dozen “nature carpets”—large rectangles decorated with foam pumpkins, cabbages, and watermelons. He wanted viewers to walk around on the carpets—which meant they had to be durable. Unfortunately, the polyurethane foam he used is inherently unstable. It’s especially vulnerable to light damage, and by the mid-1990s, Gilardi’s pumpkins, roses, and other figures were splitting and crumbling. Museums locked some of them away in the dark. So van Oosten and her colleagues worked to preserve Gilardi’s sculptures. They infused some with stabilizing and consolidating chemicals. Van Oosten calls those chemicals “sunscreens” because their goal was to prevent further light damage and rebuild worn polymer fibers. She is proud that several sculptures have even gone on display again, albeit sometimes beneath protective cases. Despite success stories like van Oosten’s, preservation of plastics will likely get harder. Old objects continue to deteriorate. Worse, biodegradable plastics, designed to disintegrate, are increasingly common. And more is at stake here than individual objects. Joana Lia Ferreira, an assistant professor of conservation and restoration at the NOVA School of Science and Technology, notes that archaeologists first defined the great material ages of human history—Stone Age, Iron Age, and so on—after examining artifacts in museums. We now live in an age of plastic, she says, “and what we decide to collect today, what we decide to preserve...will have a strong impact on how in the future we’ll be seen.”',
    5,
    5.00,
    1,
    20221,
    NULL
) ON DUPLICATE KEY UPDATE
