INSERT INTO kyyy_reading_passage (
    passage_code, exam_direction, source_year, source_name, passage_no, title, passage_text,
    question_count, total_score, status, sort_no, created_by
) VALUES (
    'kyyy-e1-2025-text4',
    'english_one',
    2025,
    '2025 年考研英语（一）阅读理解',
    4,
    NULL,
    'Visit any antiques stores and you may encounter artifact from the past: photographs, letters, a brochure Sinclair dinosaur 1964-1965 Fair, the ephemera of history. Yet they aren’t truly ephemeral. Why? Because they are still here, decades, and they are tangible. Have you pondered the life cycle of intangible formats, digital information, given that those who produce these artifacts seldom make provision for their long-term preservation? For millennia we’ve known what we’ve known due to artifacts that have survived, often despite their original creators’ neglect. The thing itself is the medium that delivers the information. At the time of creation, no attempts were made at intentional preservation, yet analog materials have a chance of surviving and serving as the historical record that biographers, historians, and novelists rely on. Libraries and archives have, traditionally shouldered the responsibility of organization, preservation, and access to information. Thus, librarians digitize the tangible so that researchers the world over can quickly search and access their holdings. The result is an embarrassment of historical riches, which brings its own needle-and-haystack problems. Librarians selfless devotion can act against us when users point to universality of access by holding up a cellphone and saying, “it’s all in here” as evidence that libraries are less vital for researchers today. Yet how was that universality of access of made possible and, perhaps more importantly, how is it maintained? Who curates what is preserved? When it comes to born-digital information, the terrifying answer can be: if not librarians and archivists, then no one. Digital information requires a great deal more care than analog. Even when a digital object is preserved, it may only be the carrier that’s saved, not the information itself. As technology advances and a format becomes obsolete, the object is useless. Have you ever stared helplessly at a ZIP disk, think how do I get the files off this? Without constant migration of digital assets a nightmare about what keeps historians up at night: a historical record that abrupt stops when digital assets replaces analog. As a librarian whose day job revolves around special collections and digital assets, I share the night terrors of historians, and I’d be lying if I said a comprehensive preservation solution currently exists. Yet researchers can take some comfort in the fact that there are a multitude of librarians devoted to discovering, organizing, and preserving digital information for researchers current and future. Librarians are uniquely positioned to understand how end users seek and use information. Thus we play an integral role in identifying, preserving, and providing accessibility to digital artifacts so that, while future researchers may find the digital realm a challenging place to ply their trade, they won’t find it an impossible one.',
    5,
    5.00,
    1,
    20254,
    NULL
) ON DUPLICATE KEY UPDATE
